const inp = $input.item.json;
const body = inp.body || inp;
const question = (body.question || body.topic || body.message || '').toString().trim();
if (!question) {
  return [{ json: { ok: false, skip: true, reason: 'Missing question/topic in request body' } }];
}
const sessionId = `LRC-${Date.now()}`;
const context = (body.context || '').toString().trim();
return [{ json: { ok: true, skip: false, sessionId, question, context } }];

const base = $('normalize_input').first().json;
const webRaw = $('search_web').first().json || {};
const ragRaw = $('search_rag').first().json || {};

const webResults = Array.isArray(webRaw.results) ? webRaw.results.slice(0, 5) : [];
const webContext = webResults.map((r, i) => `[${i+1}] ${r.title || ''}: ${r.url || ''}`).join('\n') || 'No web results';

const ragDocs = ragRaw.documents ? ragRaw.documents[0] || [] : [];
const ragDistances = ragRaw.distances ? ragRaw.distances[0] || [] : [];
const ragContext = ragDocs.slice(0, 8).map((d, i) => `[RAG-${i+1}] (dist: ${ragDistances[i]?.toFixed(3) || '?'}): ${typeof d === 'string' ? d.slice(0, 500) : ''}`).join('\n') || 'No RAG results';

return [{ json: { ...base, webContext, ragContext, webCount: webResults.length, ragCount: ragDocs.length } }];

const base = $('merge_context').first().json;
const getReply = (nodeName) => {
  try {
    const r = $(nodeName).first().json;
    return r.choices?.[0]?.message?.content || r.error || 'No response from ' + nodeName;
  } catch(e) { return 'Error: ' + e.message; }
};
const affirmativeArg = getReply('analyst_affirmative');
const negativeArg = getReply('analyst_negative');
return [{ json: { ...base, affirmativeArg, negativeArg, debateRound: 1 } }];

const base = $('collect_debate_r1').first().json;
const getReply = (nodeName) => {
  try {
    const r = $(nodeName).first().json;
    return r.choices?.[0]?.message?.content || r.error || 'No response from ' + nodeName;
  } catch(e) { return 'Error: ' + e.message; }
};
const rebuttalAff = getReply('rebuttal_affirmative');
const rebuttalNeg = getReply('rebuttal_negative');
return [{ json: { ...base, rebuttalAff, rebuttalNeg, debateRound: 2 } }];

const base = $('collect_debate_r2').first().json;
const judgeRaw = $input.item.json;
const verdict = judgeRaw.choices?.[0]?.message?.content || 'No verdict generated';
const now = new Date();
const filename = `${base.sessionId}_legal_review.md`;
const filepath = `/app/logs/council_sessions/${filename}`;

const report = [
  '# Legal Review Council Session (MAD Debate)',
  '',
  `**Session ID:** ${base.sessionId}`,
  `**Date:** ${now.toISOString()}`,
  `**Legal Question:** ${base.question}`,
  `**Web Sources:** ${base.webCount} | **RAG Sources:** ${base.ragCount}`,
  '',
  '## Round 1: Opening Arguments',
  '',
  '### Affirmative Analyst',
  base.affirmativeArg,
  '',
  '### Negative Analyst',
  base.negativeArg,
  '',
  '## Round 2: Rebuttals',
  '',
  '### Affirmative Rebuttal',
  base.rebuttalAff,
  '',
  '### Negative Rebuttal',
  base.rebuttalNeg,
  '',
  '## Judge Verdict',
  verdict,
  '',
  '---',
  '*This is an advisory opinion, not legal advice.*'
].join('\n');

const b64 = Buffer.from(report, 'utf8').toString('base64');
return [{
  json: { sessionId: base.sessionId, filepath, question: base.question, verdict, webCount: base.webCount, ragCount: base.ragCount },
  binary: { reportData: { data: b64, mimeType: 'text/markdown', fileName: filename } }
}];

const inp = $input.item.json || {};
const fail = $('normalize_input').first().json || {};
if (fail.skip === true) {
  return [{ json: { status: 'rejected', council: 'legal_review', message: fail.reason } }];
}
const built = $('build_session_report').first().json || {};
return [{ json: {
  status: 'success',
  council: 'legal_review',
  sessionId: built.sessionId || 'unknown',
  question: built.question || '',
  verdict: built.verdict || '',
  sources: { web: built.webCount || 0, rag: built.ragCount || 0 },
  reportPath: built.filepath || '',
  disclaimer: 'Advisory opinion only - not legal advice'
} }];
